import { Component, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { Invoice, InvoiceStatus } from '../../core/models';

@Component({
  selector: 'app-invoices-list',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './invoices-list.component.html',
})
export class InvoicesListComponent {
  private route = inject(ActivatedRoute);

  invoices = signal<Invoice[]>([
    {
      id: 'inv1',
      number: 'INV-3001',
      salesOrderId: 'so4',
      customerId: 'c1',
      customerName: 'Northwind Traders',
      status: 'open',
      issuedAt: '2026-07-02',
      paidAt: null,
      lines: [
        { id: 'il1', productId: 'p8', productName: 'Proximity Sensor', sku: 'SEN-200', qty: 15, unitPrice: 49.0 },
      ],
      total: 735,
    },
    {
      id: 'inv2',
      number: 'INV-3002',
      salesOrderId: 'so9',
      customerId: 'c2',
      customerName: 'Contoso Ltd',
      status: 'open',
      issuedAt: '2026-07-05',
      paidAt: null,
      lines: [
        { id: 'il2', productId: 'p7', productName: 'Control Panel', sku: 'PNL-100', qty: 15, unitPrice: 320.0 },
        { id: 'il3', productId: 'p5', productName: 'Copper Wire 14AWG', sku: 'WIR-014', qty: 12, unitPrice: 23.79 },
      ],
      total: 5085.5,
    },
    {
      id: 'inv3',
      number: 'INV-3000',
      salesOrderId: 'so8',
      customerId: 'c3',
      customerName: 'Fabrikam Inc',
      status: 'paid',
      issuedAt: '2026-06-28',
      paidAt: '2026-07-01',
      lines: [
        { id: 'il4', productId: 'p3', productName: 'PVC Pipe 50mm', sku: 'PIP-050', qty: 40, unitPrice: 7.5 },
        { id: 'il5', productId: 'p1', productName: 'Steel Bolt M8', sku: 'STL-001', qty: 100, unitPrice: 1.2 },
      ],
      total: 420,
    },
  ]);

  status = signal<string>(this.route.snapshot.queryParamMap.get('status') ?? '');

  filtered = computed(() => {
    const s = this.status();
    if (!s) {
      return this.invoices();
    }
    return this.invoices().filter((i) => i.status === s);
  });

  openInvoices = computed(() => this.invoices().filter((i) => i.status === 'open'));
  openCount = computed(() => this.openInvoices().length);
  openSum = computed(() => this.openInvoices().reduce((acc, i) => acc + i.total, 0));

  constructor() {
    this.route.queryParamMap.subscribe((params) => {
      this.status.set(params.get('status') ?? '');
    });
  }

  statusBadge(s: InvoiceStatus): string {
    return s === 'paid' ? 'badge-success' : 'badge-warning';
  }
}
